export const BlogService = {
  // Get all posts from storage or return initial seed data
  getAllPosts: (): BlogPost[] => {
    const storedPosts = localStorage.getItem(STORAGE_KEY);
    if (!storedPosts) {
      // First time load: save initial data to storage so we can add to it later
      localStorage.setItem(STORAGE_KEY, JSON.stringify(INITIAL_POSTS));
      return INITIAL_POSTS;
    }
    return JSON.parse(storedPosts);
  },

  // Add a new post
  addPost: (post: Omit<BlogPost, 'id' | 'date' | 'readTime'>) => {
    const posts = BlogService.getAllPosts();

    // Calculate read time roughly (200 words per minute)
    const wordCount = post.excerpt.split(' ').length + 500; // Assuming full content is roughly 500 words more than excerpt
    const readTime = Math.ceil(wordCount / 200) + ' min read';

    const newPost: BlogPost = {
      ...post,
      id: Date.now().toString(),
      date: new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }),
      readTime,
      isFeatured: false // New uploads are not featured by default, just added to grid
    };

    // Add new post to the beginning of the array (after featured)
    const featured = posts.find(p => p.isFeatured);
    const others = posts.filter(p => !p.isFeatured);

    // Construct new list: Featured -> New Post -> Others
    const updatedList = featured ? [featured, newPost, ...others] : [newPost, ...others];

    localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedList));
    return newPost;
  }
};

