  onClose: () => void;
  onPostAdded: () => void;
}

const categories = ['Product Management', 'Design', 'Engineering', 'Career', 'Tech Trends', 'Data Analytics'];

export const BlogUploadModal: React.FC<BlogUploadModalProps> = ({ isOpen, onClose, onPostAdded }) => {
  const [formData, setFormData] = useState({
    title: '',
    excerpt: '',
    author: '',
    category: categories[0],
    image: ''
  });

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title || !formData.author || !formData.excerpt) return;

    // Use a placeholder image if none provided
    const imageToUse = formData.image || 'https://images.unsplash.com/photo-1519389950473-47ba0277781c?auto=format&fit=crop&q=80&w=1000';

    BlogService.addPost({
      ...formData,
      image: imageToUse
    });

    onPostAdded();
    onClose();
    // Reset form
    setFormData({
      title: '',
      excerpt: '',
      author: '',
      category: categories[0],
      image: ''
    });
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
