export interface BlogPost {
  id: string;
  title: string;
  excerpt: string;
  content: string;
  author: string;
  authorImage?: string;
  date: string;
  readTime: string;
  category: string;
  image: string;
  isFeatured?: boolean;
}

import { BlogPost } from '../types';

const STORAGE_KEY = 'pha_blog_posts_v2'; // Changed version to reset storage

// Cleared Mock Data as requested
const INITIAL_POSTS: BlogPost[] = [];

export const BlogService = {
  // Get all posts from storage or return initial seed data
  getAllPosts: (): BlogPost[] => {
    const storedPosts = localStorage.getItem(STORAGE_KEY);
    if (!storedPosts) {
      // First time load
      localStorage.setItem(STORAGE_KEY, JSON.stringify(INITIAL_POSTS));
      return INITIAL_POSTS;
    }
    return JSON.parse(storedPosts);
  },

  // Add a new post
  addPost: (post: Omit<BlogPost, 'id' | 'date' | 'readTime'>) => {
    const posts = BlogService.getAllPosts();

    // Calculate read time roughly (200 words per minute)
    // Use content if available, otherwise excerpt
    const textToMeasure = post.content || post.excerpt;
    const wordCount = textToMeasure.split(/\s+/).length;
    const readTime = Math.max(1, Math.ceil(wordCount / 200)) + ' min read';

    const newPost: BlogPost = {
      ...post,
      id: Date.now().toString(),
      date: new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }),
      readTime,
    };

    // If new post is featured, unfeature others if we want only one featured (optional logic, but typically good)
    // For now, we'll just add it to the list.

    // Add new post to the beginning of the array
    // If it's featured, it goes to very top.
    let updatedList = [];

    if (newPost.isFeatured) {
        // If new one is featured, put it first, then others
        updatedList = [newPost, ...posts];
    } else {
        // If not featured, put it after any existing featured posts (or just at top if simplicity is preferred)
        // Let's just put it at the top for "Latest"
        updatedList = [newPost, ...posts];
    }

    localStorage.setItem(STORAGE_KEY, JSON.stringify(updatedList));
    return newPost;
  }
};

