  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title || !formData.author || !formData.excerpt) return;

    // Use a placeholder image if none provided
    const imageToUse = formData.image || 'https://images.unsplash.com/photo-1519389950473-47ba0277781c?auto=format&fit=crop&q=80&w=1000';

    BlogService.addPost({
      ...formData,
      image: imageToUse
    });

