import { db } from '../lib/firebase';
import { collection, getDocs, addDoc, query, orderBy, Timestamp } from 'firebase/firestore';
import { BlogPost } from '../types';

export const BlogService = {
  // Get all posts from Firestore
  getAllPosts: async (): Promise<BlogPost[]> => {
    try {
      // Query posts collection, sort by createdAt descending (newest first)
      const postsRef = collection(db, 'posts');
      // Note: For orderBy to work perfectly, you might need to create an index in Firebase Console
      // if it complains, check the browser console for a direct link to create it.
      // Falling back to simple getDocs for initial setup to avoid index errors for beginners.

      const snapshot = await getDocs(postsRef);

      const posts = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          ...data
        } as BlogPost;
      });

      // Manual Sort in Javascript just to be safe if index isn't created yet
      // Assuming we save a 'createdAt' timestamp
      return posts.sort((a: any, b: any) => {
         const timeA = a.createdAt ? new Date(a.createdAt).getTime() : 0;
         const timeB = b.createdAt ? new Date(b.createdAt).getTime() : 0;
         return timeB - timeA;
      });

    } catch (error) {
      console.error("Error fetching blog posts:", error);
      // Fallback to empty array so app doesn't crash
      return [];
    }
  },

  // Add a new post to Firestore
  addPost: async (post: Omit<BlogPost, 'id' | 'date' | 'readTime'>): Promise<BlogPost | null> => {
    try {
      // Calculate read time roughly (200 words per minute)
      const textToMeasure = post.content || post.excerpt;
      const wordCount = textToMeasure.split(/\s+/).length;
      const readTime = Math.max(1, Math.ceil(wordCount / 200)) + ' min read';

      const dateString = new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });

      const newPostData = {
        ...post,
        date: dateString,
        readTime,
        createdAt: new Date().toISOString() // Helper for sorting
      };

      const docRef = await addDoc(collection(db, 'posts'), newPostData);

      return {
        id: docRef.id,
        ...newPostData
      } as BlogPost;

    } catch (error) {
      console.error("Error adding blog post:", error);
      alert("Failed to save article. Check your Firebase config and Console.");
      return null;
    }
  }
};

import React, { useState, useEffect } from 'react';
import { TYPOGRAPHY } from '../../constants';
import { Clock, User, ChevronRight, PenTool, Plus, Layers, Loader2 } from 'lucide-react';
import { Button } from '../../components/Button';
import { Reveal } from '../../components/Reveal';
import { BlogService } from '../../services/blogService';
import { BlogPost } from '../../types';
import { BlogEditorCanvas } from '../../components/BlogEditorCanvas';

const categories = ['All', 'Product Management', 'Design', 'Engineering', 'Career', 'Tech Trends', 'Data Analytics'];

export const BlogPage: React.FC = () => {
  const [activeCategory, setActiveCategory] = useState('All');
  const [posts, setPosts] = useState<BlogPost[]>([]);
  const [isEditorOpen, setIsEditorOpen] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  // Fetch posts on mount
  useEffect(() => {
    loadPosts();
  }, []);

  const loadPosts = async () => {
    setIsLoading(true);
    const allPosts = await BlogService.getAllPosts();
    setPosts(allPosts);
    setIsLoading(false);
  };

  // Determine Featured Post (First one found, or first in list)
  const featuredPost = posts.find(p => p.isFeatured) || (posts.length > 0 ? posts[0] : undefined);

  // Filter grid posts (Exclude featured post from grid to avoid duplication, unless searching categories)
  const gridPosts = posts.filter(p => {
    const matchesCategory = activeCategory === 'All' || p.category === activeCategory;
    const isNotFeatured = featuredPost ? p.id !== featuredPost.id : true;
    return matchesCategory && (activeCategory === 'All' ? isNotFeatured : true);
  });

  return (
    <div 
      className="w-full pb-[100px] md:pb-[160px] pt-[160px] md:pt-[240px]"
      style={{
        background: 'radial-gradient(rgba(252, 211, 77, 0.2) 2px, transparent 2px), linear-gradient(to bottom, #f0f6fa, #ffffff)',
        backgroundSize: '30px 30px, 100% 100%'
      }}
    >
      <BlogEditorCanvas 
        isOpen={isEditorOpen} 
        onClose={() => setIsEditorOpen(false)} 
        onPostAdded={loadPosts} 
      />

      <div className="container mx-auto px-6">
        {/* Header */}
        <Reveal width="100%" className="text-center mb-16">
          <span className="text-[#135291] font-bold tracking-wider uppercase text-sm mb-3 block">Our Blog</span>
          <h1 className={`${TYPOGRAPHY.header01} text-[#08223d] mb-6`}>Insights & Perspectives</h1>
          <p className={`${TYPOGRAPHY.body02} max-w-2xl mx-auto text-gray-500 mb-8`}>
            Expert advice, industry trends, and success stories to help you navigate your tech career.
          </p>

          {/* Admin Action */}
          <div className="flex justify-center">
            <button 
              onClick={() => setIsEditorOpen(true)}
              className="inline-flex items-center px-6 py-3 bg-[#e7eef4] text-[#135291] rounded-full font-bold hover:bg-[#135291] hover:text-white transition-all duration-300 shadow-md hover:shadow-lg transform hover:-translate-y-1"
            >
              <Plus size={18} className="mr-2" /> Write an Article
            </button>
          </div>
        </Reveal>

        {/* Categories */}
        <div className="flex flex-wrap justify-center gap-4 mb-24">
          {categories.map((cat) => (
            <button
              key={cat}
              onClick={() => setActiveCategory(cat)}
              className={`px-8 py-3 rounded-full font-medium transition-all duration-300 border ${
                activeCategory === cat
                  ? 'bg-[#135291] text-white border-[#135291]'
                  : 'bg-white text-gray-600 border-gray-200 hover:border-[#135291] hover:text-[#135291]'
              }`}
            >
              {cat}
            </button>
          ))}
        </div>

        {/* Loading State */}
        {isLoading && (
          <div className="flex justify-center py-20">
             <Loader2 size={40} className="text-[#135291] animate-spin" />
          </div>
        )}

        {/* Empty State */}
        {!isLoading && posts.length === 0 && (
          <div className="text-center py-32 bg-white rounded-[32px] border border-dashed border-gray-300 max-w-4xl mx-auto mb-20">
             <div className="w-20 h-20 bg-gray-50 rounded-full flex items-center justify-center mx-auto mb-6 text-gray-400">
                <Layers size={32} />
             </div>
             <h3 className="text-2xl font-bold text-[#08223d] mb-2">No articles yet</h3>
             <p className="text-gray-500 mb-8">Be the first to share insights with the community.</p>
             <Button onClick={() => setIsEditorOpen(true)}>Start Writing</Button>
          </div>
        )}

        {/* Featured Post - Only show if All categories selected and we have a post */}
        {!isLoading && activeCategory === 'All' && featuredPost && (
          <Reveal width="100%" className="mb-32">
            <div className="group relative rounded-xl md:rounded-3xl overflow-hidden bg-white grid md:grid-cols-2 cursor-pointer border border-gray-100 shadow-sm hover:shadow-md transition-all duration-500">
              <div className="relative h-64 md:h-auto overflow-hidden">
