                    <ChevronRight size={24} />
                  </div>
                </div>
              </div>
            </div>
          </Reveal>
        )}

        {/* Recent Posts Grid */}
        {!isLoading && gridPosts.length > 0 && (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-12">
            {gridPosts.map((post, i) => (
