import React, { useState } from 'react';
import { X, Image as ImageIcon, Upload, User, Check, AlignLeft, Type, Layout, Loader2 } from 'lucide-react';
import { Button } from './Button';
import { TYPOGRAPHY, COLORS } from '../constants';
import { BlogService } from '../services/blogService';

interface BlogEditorCanvasProps {
  isOpen: boolean;
  onClose: () => void;
  onPostAdded: () => void;
}

const categories = ['Product Management', 'Design', 'Engineering', 'Career', 'Tech Trends', 'Data Analytics'];

export const BlogEditorCanvas: React.FC<BlogEditorCanvasProps> = ({ isOpen, onClose, onPostAdded }) => {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    title: '',
    excerpt: '',
    content: '',
    author: '',
    authorImage: '',
    category: categories[0],
    image: '',
    isFeatured: false
  });

  if (!isOpen) return null;

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title || !formData.author || !formData.excerpt) {
        alert("Please fill in the Title, Author, and Excerpt.");
        return;
    }

    setIsSubmitting(true);

    // Use a placeholder image if none provided
    const imageToUse = formData.image || 'https://images.unsplash.com/photo-1519389950473-47ba0277781c?auto=format&fit=crop&q=80&w=1000';

    const result = await BlogService.addPost({
      ...formData,
      image: imageToUse
    });

    setIsSubmitting(false);

    if (result) {
        onPostAdded();
        onClose();
        // Reset form
        setFormData({
            title: '',
            excerpt: '',
            content: '',
            author: '',
            authorImage: '',
            category: categories[0],
            image: '',
            isFeatured: false
        });
    }
  };

  // Prevent background scroll
  React.useEffect(() => {
    if (isOpen) {
      document.body.style.overflow = 'hidden';
    } else {
      document.body.style.overflow = 'unset';
    }
    return () => { document.body.style.overflow = 'unset'; }
  }, [isOpen]);

  return (
    <div className="fixed inset-0 z-[100] flex justify-end">
      {/* Backdrop */}
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm transition-opacity" onClick={onClose}></div>

      {/* Canvas Container */}
      <div className="relative w-full md:w-[85vw] lg:w-[70vw] h-full bg-white shadow-2xl flex flex-col animate-slide-in-right">

        {/* Header */}
        <div className="flex justify-between items-center px-8 py-5 border-b border-gray-100 bg-white/80 backdrop-blur-md sticky top-0 z-20">
          <div className="flex items-center gap-4">
             <button onClick={onClose} className="p-2 hover:bg-gray-100 rounded-full transition-colors text-gray-500">
                <X size={24} />
             </button>
             <h2 className={`${TYPOGRAPHY.header03} text-[#08223d]`}>New Article</h2>
          </div>
          <div className="flex items-center gap-4">
             <span className="text-sm text-gray-400 hidden sm:inline">
                 {isSubmitting ? 'Saving to Firebase...' : 'Ready to publish'}
             </span>
             <Button 
                onClick={handleSubmit} 
                size="md" 
                className="shadow-lg shadow-blue-500/20"
                disabled={isSubmitting}
             >
                {isSubmitting ? (
                    <Loader2 size={18} className="mr-2 animate-spin" />
                ) : (
                    <Upload size={18} className="mr-2" />
                )}
                {isSubmitting ? 'Publishing...' : 'Publish'}
             </Button>
          </div>
        </div>

        {/* Scrollable Content */}
        <div className="flex-1 overflow-y-auto bg-[#fafafa]">
           <div className="max-w-5xl mx-auto p-8 md:p-12">

              <div className="grid grid-cols-1 lg:grid-cols-3 gap-12">

                 {/* Main Content Column */}
                 <div className="lg:col-span-2 space-y-8">

                    {/* Cover Image */}
                    <div className="group relative w-full h-64 md:h-80 bg-gray-100 rounded-2xl border-2 border-dashed border-gray-300 flex flex-col items-center justify-center overflow-hidden transition-all hover:border-[#135291]">
                       {formData.image ? (
                          <>
                            <img src={formData.image} alt="Cover" className="w-full h-full object-cover" />
                            <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center">
                               <p className="text-white font-bold">Change Image</p>
                            </div>
                          </>
                       ) : (
                          <div className="text-center p-6">
                             <ImageIcon size={48} className="mx-auto text-gray-300 mb-4" />
                             <p className="text-gray-500 font-medium">Add Cover Image</p>
                             <p className="text-xs text-gray-400 mt-2">Paste URL below</p>
                          </div>
                       )}
                       <input 
                          type="url" 
                          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                          value={formData.image}
