                       <label className="flex items-center gap-2 text-sm font-bold text-gray-400 mb-2 uppercase tracking-wide">
                          <AlignLeft size={16} /> Summary / Excerpt
                       </label>
                       <textarea 
                         rows={3}
                         placeholder="Write a short summary that appears on the card..." 
                         className="w-full text-lg text-gray-600 placeholder-gray-300 bg-white border border-gray-200 rounded-xl p-4 focus:ring-2 focus:ring-[#135291] outline-none resize-none transition-shadow"
