                         onChange={(e) => setFormData({...formData, excerpt: e.target.value})}
                       />
                    </div>

                    {/* Full Content */}
                    <div>
                       <label className="flex items-center gap-2 text-sm font-bold text-gray-400 mb-2 uppercase tracking-wide">
                          <Type size={16} /> Article Content
                       </label>
                       <textarea 
