                         placeholder="Write your story here..." 
                         className="w-full text-lg text-[#08223d] placeholder-gray-300 bg-white border border-gray-200 rounded-xl p-6 focus:ring-2 focus:ring-[#135291] outline-none resize-y transition-shadow leading-relaxed"
                         value={formData.content}
                         onChange={(e) => setFormData({...formData, content: e.target.value})}
                       />
                    </div>
                 </div>

                 {/* Sidebar Settings */}
                 <div className="space-y-8">

                    {/* Publishing Options */}
                    <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                       <h3 className="font-bold text-[#08223d] mb-4 flex items-center gap-2">
                          <Layout size={18} /> Settings
                       </h3>

                       <div className="space-y-4">
                          <div>
                             <label className="block text-sm font-bold text-gray-700 mb-2">Category</label>
                             <select 
                               className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-[#135291] outline-none cursor-pointer"
                               value={formData.category}
                               onChange={(e) => setFormData({...formData, category: e.target.value})}
                             >
                               {categories.map(c => <option key={c} value={c}>{c}</option>)}
                             </select>
                          </div>

                          <div className="flex items-center justify-between p-3 bg-gray-50 rounded-xl border border-gray-200 cursor-pointer" onClick={() => setFormData({...formData, isFeatured: !formData.isFeatured})}>
                             <span className="text-sm font-bold text-gray-700">Set as Featured</span>
                             <div className={`w-6 h-6 rounded-md border flex items-center justify-center transition-colors ${formData.isFeatured ? 'bg-[#135291] border-[#135291]' : 'border-gray-300 bg-white'}`}>
                                {formData.isFeatured && <Check size={14} className="text-white" />}
