                               className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-[#135291] outline-none"
                               placeholder="e.g. Jane Doe"
                               value={formData.author}
                               onChange={(e) => setFormData({...formData, author: e.target.value})}
                             />
                          </div>

                          <div>
                             <label className="block text-sm font-bold text-gray-700 mb-2">Writer Image URL</label>
                             <div className="flex gap-3">
                                <input 
                                  type="url" 
                                  className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-[#135291] outline-none text-sm"
