import { db } from '../lib/firebase';
import { collection, getDocs, addDoc, query, orderBy, Timestamp } from 'firebase/firestore';
import { BlogPost } from '../types';

export const BlogService = {
  // Get all posts from Firestore
  getAllPosts: async (): Promise<BlogPost[]> => {
    try {
      // Query posts collection
      // We manually sort in JS to avoid initial "Missing Index" errors for beginners in Firestore
      const postsRef = collection(db, 'posts');

      const snapshot = await getDocs(postsRef);

      const posts = snapshot.docs.map(doc => {
        const data = doc.data();
        return {
          id: doc.id,
          ...data
        } as BlogPost;
      });

      // Sort by creation date (newest first)
      // We assume the date field is stored as string or we use a separate createdAt timestamp
      return posts.sort((a: any, b: any) => {
         const timeA = a.createdAt ? new Date(a.createdAt).getTime() : 0;
         const timeB = b.createdAt ? new Date(b.createdAt).getTime() : 0;
         return timeB - timeA;
      });

    } catch (error) {
      console.error("Error fetching blog posts:", error);
      // Fallback to empty array so app doesn't crash if config is wrong
      return [];
    }
  },

  // Add a new post to Firestore
  addPost: async (post: Omit<BlogPost, 'id' | 'date' | 'readTime'>): Promise<BlogPost | null> => {
    try {
      // Calculate read time roughly (200 words per minute)
      const textToMeasure = post.excerpt || "";
      const wordCount = textToMeasure.split(/\s+/).length + 300; // rough estimate
      const readTime = Math.max(1, Math.ceil(wordCount / 200)) + ' min read';

      const dateString = new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });

      const newPostData = {
        ...post,
        date: dateString,
        readTime,
        isFeatured: false,
        createdAt: new Date().toISOString() // Helper for sorting
      };

      const docRef = await addDoc(collection(db, 'posts'), newPostData);

      return {
        id: docRef.id,
        ...newPostData
      } as BlogPost;

    } catch (error) {
      console.error("Error adding blog post:", error);
      alert("Failed to save article. Check your Firebase config keys in lib/firebase.ts");
      return null;
    }
  }
};

