                  onChange={e => setFormData({...formData, author: e.target.value})}
                />
              </div>
              <div>
                <label className="block text-sm font-bold text-gray-700 mb-2">Category</label>
                <select 
                  className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-[#135291] outline-none cursor-pointer"
                  value={formData.category}
                  onChange={e => setFormData({...formData, category: e.target.value})}
                >
                  {categories.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
            </div>

            {/* Excerpt */}
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Short Excerpt / Summary</label>
              <textarea 
                required
                rows={4}
                className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-[#135291] outline-none"
                placeholder="Write a brief summary of the article..."
                value={formData.excerpt}
                onChange={e => setFormData({...formData, excerpt: e.target.value})}
              />
            </div>

            {/* Image URL */}
            <div>
              <label className="block text-sm font-bold text-gray-700 mb-2">Cover Image URL</label>
              <div className="flex gap-3">
                 <div className="flex-grow">
                    <input 
                      type="url" 
                      className="w-full px-4 py-3 bg-gray-50 border border-gray-200 rounded-xl focus:ring-2 focus:ring-[#135291] outline-none"
                      placeholder="https://example.com/image.jpg"
                      value={formData.image}
                      onChange={e => setFormData({...formData, image: e.target.value})}
                    />
                 </div>
                 <div className="w-12 h-12 rounded-xl bg-gray-100 flex items-center justify-center shrink-0 border border-gray-200">
                    {formData.image ? (
                        <img src={formData.image} alt="Preview" className="w-full h-full object-cover rounded-xl" onError={(e) => e.currentTarget.src = ''} />
                    ) : (
                        <ImageIcon size={20} className="text-gray-400" />
                    )}
                 </div>
              </div>
              <p className="text-xs text-gray-400 mt-2">Paste a direct link to an image (Unsplash, etc.)</p>
            </div>

            <div className="pt-4">
              <Button type="submit" fullWidth size="lg" disabled={isSubmitting}>
                {isSubmitting ? <Loader2 size={18} className="mr-2 animate-spin" /> : <Upload size={18} className="mr-2" />}
                {isSubmitting ? 'Publishing...' : 'Publish Article'}
              </Button>
            </div>

          </form>
        </div>
      </div>
    </div>
  );
};

