export const BlogService = {
  // Get all posts from Sanity
  getAllPosts: async (): Promise<BlogPost[]> => {
    try {
        // Check if user has configured Sanity
        if (sanityClient.config().projectId === 'replace_with_your_project_id') {
            return MOCK_POSTS;
        }

        const query = `*[_type == "post"] | order(publishedAt desc) {
            _id,
            title,
            excerpt,
            "slug": slug.current,
            "author": author->name,
            "authorImage": author->image.asset->url,
            publishedAt,
            "imageUrl": mainImage.asset->url,
            "category": categories[0]->title
        }`;

        const sanityPosts = await sanityClient.fetch(query);

        return sanityPosts.map((post: any) => ({
            id: post._id,
            slug: post.slug || post._id, // Fallback to ID if slug missing
            title: post.title,
            excerpt: post.excerpt || "Click to read more...",
            author: post.author || "PHA Team",
            date: post.publishedAt ? new Date(post.publishedAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }) : 'Recent',
            readTime: '5 min read',
            category: post.category || 'Tech',
            image: post.imageUrl || 'https://via.placeholder.com/800x600?text=No+Image',
            authorImage: post.authorImage
        }));

    } catch (error) {
      console.error("Error fetching blog posts:", error);
      return MOCK_POSTS;
    }
  },

  // Get single post by Slug
  getPostBySlug: async (slug: string): Promise<BlogPost | null> => {
      try {
        if (sanityClient.config().projectId === 'replace_with_your_project_id') {
             // Return a mock post with dummy content
             const mock = MOCK_POSTS.find(p => p.slug === slug || p.id === slug);
             if (mock) {
                 return {
                     ...mock,
                     content: [
                         { _type: 'block', children: [{ _type: 'span', text: "This is a mock article content. Connect Sanity to see real content." }] },
                         { _type: 'block', children: [{ _type: 'span', text: "Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua." }] }
                     ]
                 };
             }
             return null;
        }

        const query = `*[_type == "post" && slug.current == $slug][0] {
            _id,
            title,
            excerpt,
            body,
            "slug": slug.current,
            "author": author->name,
            "authorImage": author->image.asset->url,
            publishedAt,
            "imageUrl": mainImage.asset->url,
            "category": categories[0]->title
        }`;

        const post = await sanityClient.fetch(query, { slug });

        if (!post) return null;

        return {
            id: post._id,
            slug: post.slug,
            title: post.title,
            excerpt: post.excerpt,
            content: post.body,
            author: post.author || "PHA Team",
            date: post.publishedAt ? new Date(post.publishedAt).toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' }) : 'Recent',
            readTime: '5 min read',
            category: post.category || 'Tech',
            image: post.imageUrl || 'https://via.placeholder.com/800x600?text=No+Image',
            authorImage: post.authorImage
        };

      } catch (error) {
          console.error("Error fetching post:", error);
          return null;
      }
  }
};

