const PROJECT_ID = 'm47z9y0m'; 
const DATASET = 'production';

export const sanityClient = createClient({
  projectId: PROJECT_ID, 
  dataset: DATASET,
  useCdn: true,
  apiVersion: '2023-05-03',
});

/**
 * Helper to generate image URLs from Sanity image references.
 * Constructs the CDN URL: https://cdn.sanity.io/images/{projectId}/{dataset}/{filename}.{extension}
 */
export const urlFor = (source: any) => {
  if (!source || !source.asset || !source.asset._ref) return '';

  // Format of Sanity _ref is usually: image-ID-Dimensions-Format
  const ref = source.asset._ref;
  const parts = ref.split('-');

  if (parts.length < 4) return '';

  // The ref usually looks like: image-8382...-1200x800-jpg
  const id = parts[1];
  const dimensions = parts[2];
  const format = parts[3];

