            <nav className="hidden lg:flex items-center space-x-8">
              {navLinks.map((link) => (
                <div key={link.label} className="relative group h-full flex items-center">
                  {link.isMegaMenu ? (
                    <div
                      onMouseEnter={() => setIsMegaMenuOpen(true)}
