                activeCategory === cat
                  ? 'bg-[#135291] text-white border-[#135291]'
                  : 'bg-white text-gray-600 border-gray-200 hover:border-[#135291] hover:text-[#135291]'
              }`}
            >
              {cat}
            </button>
