/**
 * 👋 DESIGNER'S STEP:
 * 1. Put your WordPress link here. 
 * 2. Make sure it ends with /wp-json/wp/v2/posts?_embed
 * 3. If you don't have a link yet, leave it as "" and the site will use the "Backup Posts" below.
 */
const WP_URL = ""; 

const MOCK_POSTS: BlogPost[] = [
  {
    id: '1',
    slug: 'future-of-product-management',
    title: 'The Future of Product Management in Africa (Backup)',
    excerpt: 'Exploring how the African tech landscape is shaping the next generation of product leaders.',
    content: "The tech ecosystem in Africa is experiencing an unprecedented boom...",
    author: 'Victoria Oladosu',
    date: 'Oct 15, 2023',
    readTime: '5 min read',
    category: 'Product Management',
    image: 'https://images.unsplash.com/photo-1573164713988-8665fc963095?auto=format&fit=crop&q=80&w=1000',
    isFeatured: true
  }
];

// Helper to strip HTML tags from WordPress text (like <p> or <strong>)
const stripHtml = (html: string) => {
  const doc = new DOMParser().parseFromString(html, 'text/html');
  return doc.body.textContent || "";
};

export const BlogService = {
  getAllPosts: async (): Promise<BlogPost[]> => {
    if (!WP_URL) {
      return new Promise(resolve => setTimeout(() => resolve(MOCK_POSTS), 500));
    }

    try {
      const response = await fetch(WP_URL);
      if (!response.ok) throw new Error('WordPress fetch failed');
      const wpPosts = await response.json();

      return wpPosts.map((post: any): BlogPost => {
        // WordPress hides the image deep inside the "_embedded" section
        const featuredMedia = post._embedded?.['wp:featuredmedia']?.[0];
        const imageUrl = featuredMedia?.source_url || 'https://via.placeholder.com/800x600?text=No+Image';

        // WordPress hides the author name here
        const authorName = post._embedded?.['author']?.[0]?.name || 'Admin';

        return {
          id: post.id.toString(),
          slug: post.slug,
          title: post.title.rendered,
          excerpt: stripHtml(post.excerpt.rendered).substring(0, 160) + '...',
          content: post.content.rendered, // We keep the HTML for the post page
          author: authorName,
          date: new Date(post.date).toLocaleDateString('en-GB', { day: 'numeric', month: 'short', year: 'numeric' }),
          readTime: `${Math.ceil(post.content.rendered.split(' ').length / 200)} min read`,
          category: post._embedded?.['wp:term']?.[0]?.[0]?.name || 'Tech',
          image: imageUrl,
          isFeatured: false
        };
      });
    } catch (error) {
      console.error("WordPress Error:", error);
      return MOCK_POSTS; // Return backup posts if WordPress fails
    }
  },

  getPostBySlug: async (slug: string): Promise<BlogPost | null> => {
    const allPosts = await BlogService.getAllPosts();
    return allPosts.find(p => p.slug === slug || p.id === slug) || null;
  }
};

