 *    - category (text)
 *    - image (asset)
 * 3. CONTENT: Create your posts inside a folder named "blog".
 * 4. TOKEN: Get your "Public" or "Preview" access token from Settings -> Access Tokens.
 * 5. URL: Paste your token below.
 */

const STORYBLOK_TOKEN: string = ""; // PASTE YOUR STORYBLOK ACCESS TOKEN HERE
