    }

    try {
      // Fetching all stories from the 'blog/' folder
      const response = await fetch(
        `${STORYBLOK_BASE_URL}?token=${STORYBLOK_TOKEN}&starts_with=blog/&version=published&cv=${Date.now()}`
      );

      if (!response.ok) throw new Error('Storyblok API Error');

      const data = await response.json();

      return data.stories.map((story: any): BlogPost => {
        const { content, created_at, slug, id } = story;

        return {
