export const BlogService = {
  getAllPosts: async (): Promise<BlogPost[]> => {
    if (!STORYBLOK_TOKEN || STORYBLOK_TOKEN.trim() === "") {
      return BACKUP_POSTS;
    }

    try {
      // Step 1: Try fetching from the 'blog/' folder first (best practice)
      let url = `${STORYBLOK_BASE_URL}?token=${STORYBLOK_TOKEN}&starts_with=blog/&version=draft&cv=${Date.now()}`;
      let response = await fetch(url);
      let data = await response.json();

      // Step 2: Fallback - if no stories in 'blog/', try fetching everything
      if (!data.stories || data.stories.length === 0) {
        url = `${STORYBLOK_BASE_URL}?token=${STORYBLOK_TOKEN}&version=draft&cv=${Date.now()}`;
        response = await fetch(url);
        data = await response.json();
      }

      if (!data.stories || data.stories.length === 0) {
        return BACKUP_POSTS;
      }

      return data.stories.map((story: any): BlogPost => {
        const { content, created_at, slug, id, tag_list } = story;

        // Use full slug but remove prefix for clean internal navigation
        const cleanSlug = slug.includes('/') ? slug.split('/').pop() : slug;

        return {
          id: id.toString(),
          slug: slug, // Keep full slug for API fetching
          title: content.title || story.name,
          excerpt: content.excerpt || '',
          content: content.content || '',
          author: content.author || 'PHA Contributor',
          date: new Date(created_at).toLocaleDateString('en-GB', { 
            day: 'numeric', 
            month: 'short', 
            year: 'numeric' 
          }),
          readTime: `${Math.max(1, Math.ceil((content.content?.split(' ').length || 0) / 200))} min read`,
          category: content.category || 'Tech',
          image: content.image?.filename || 'https://images.unsplash.com/photo-1519389950473-47ba0277781c?auto=format&fit=crop&q=80&w=1000',
          isFeatured: tag_list?.includes('featured') || false
        };
      });
    } catch (error) {
      console.error("Storyblok Error:", error);
      return BACKUP_POSTS;
    }
  },

  getPostBySlug: async (slug: string): Promise<BlogPost | null> => {
    if (!STORYBLOK_TOKEN) return null;

    try {
      // We check both the exact slug and the blog/ prefixed slug
      const response = await fetch(
        `${STORYBLOK_BASE_URL}/${slug}?token=${STORYBLOK_TOKEN}&version=draft`
      );

      if (!response.ok) {
        // Try with blog/ prefix if direct failed
        const altResponse = await fetch(
          `${STORYBLOK_BASE_URL}/blog/${slug}?token=${STORYBLOK_TOKEN}&version=draft`
        );
        if (!altResponse.ok) return null;
        const altData = await altResponse.json();
        return mapStoryToBlogPost(altData.story);
      }

      const data = await response.json();
      return mapStoryToBlogPost(data.story);
    } catch (error) {
      return null;
    }
  }
};

function mapStoryToBlogPost(story: any): BlogPost {
  const { content, created_at, id, tag_list, slug } = story;
  return {
    id: id.toString(),
    slug: slug,
    title: content.title || story.name,
    excerpt: content.excerpt || '',
    content: content.content || '',
    author: content.author || 'PHA Contributor',
    date: new Date(created_at).toLocaleDateString('en-GB', { 
      day: 'numeric', 
      month: 'short', 
      year: 'numeric' 
    }),
    readTime: `${Math.max(1, Math.ceil((content.content?.split(' ').length || 0) / 200))} min read`,
    category: content.category || 'Tech',
    image: content.image?.filename || 'https://images.unsplash.com/photo-1519389950473-47ba0277781c?auto=format&fit=crop&q=80&w=1000',
    isFeatured: tag_list?.includes('featured') || false
  };
}

