const STORYBLOK_TOKEN: string = "vwemw76ExzAd6IfAAaQgEAtt"; 
const STORYBLOK_BASE_URL = "https://api.storyblok.com/v2/cdn/stories";

const BACKUP_POSTS: BlogPost[] = [
  {
    id: 'guide-1',
    slug: 'connecting-storyblok',
    title: 'Almost There! Folder Found',
    excerpt: 'Your "Articles" folder is now connected. If you see this, make sure your posts are published inside that folder.',
    content: `
      <h2>Success! The token is connected.</h2>
      <p>Your React app is now looking for content in your <strong>Articles</strong> folder. To see your actual content here:</p>
      <ol>
        <li>Go to <strong>Content</strong> in Storyblok.</li>
        <li>Open your <strong>Articles</strong> folder.</li>
        <li>Create or Move Stories into this folder.</li>
        <li>Ensure they use the <strong>blogPost</strong> content type.</li>
        <li>Click <strong>Save & Publish</strong>.</li>
      </ol>
      <p>Refresh this page and your posts will appear!</p>
    `,
    author: 'PHA Tech Team',
    date: 'Oct 2023',
    readTime: '2 min read',
    category: 'Setup',
    image: 'https://images.unsplash.com/photo-1498050108023-c5249f4df085?auto=format&fit=crop&q=80&w=1200',
    isFeatured: true
  }
];

export const BlogService = {
  getAllPosts: async (): Promise<BlogPost[]> => {
    if (!STORYBLOK_TOKEN || STORYBLOK_TOKEN.trim() === "") {
      return BACKUP_POSTS;
    }

    try {
      // Step 1: Fetch specifically from the 'Articles/' folder as identified by user
      const url = `${STORYBLOK_BASE_URL}?token=${STORYBLOK_TOKEN}&starts_with=Articles/&version=draft&cv=${Date.now()}`;
      const response = await fetch(url);

      if (!response.ok) throw new Error('Storyblok connection failed');

      const data = await response.json();

      // If no stories are found in the 'Articles/' folder, show the setup guide
      if (!data.stories || data.stories.length === 0) {
        console.warn("No stories found in 'Articles/' folder.");
        return BACKUP_POSTS;
      }

      return data.stories.map((story: any): BlogPost => {
        const { content, created_at, slug, id, tag_list } = story;

        // We want the clean slug (without the 'Articles/' prefix) for internal app routing
        // but we'll use the full slug for fetching specific posts
        return {
          id: id.toString(),
          slug: slug, // Keep the full path e.g., 'Articles/my-post'
          title: content.title || story.name,
          excerpt: content.excerpt || '',
          content: content.content || '',
          author: content.author || 'PHA Contributor',
          date: new Date(created_at).toLocaleDateString('en-GB', { 
            day: 'numeric', 
            month: 'short', 
            year: 'numeric' 
          }),
          readTime: `${Math.max(1, Math.ceil((content.content?.split(' ').length || 0) / 200))} min read`,
          category: content.category || 'Tech',
          image: content.image?.filename || 'https://images.unsplash.com/photo-1519389950473-47ba0277781c?auto=format&fit=crop&q=80&w=1000',
          isFeatured: tag_list?.includes('featured') || false
        };
      });
    } catch (error) {
      console.error("Storyblok Error:", error);
      return BACKUP_POSTS;
    }
  },

  getPostBySlug: async (fullSlug: string): Promise<BlogPost | null> => {
    if (!STORYBLOK_TOKEN) return null;

    try {
      // The fullSlug comes in as "Articles/something" from the URL parameters
      const response = await fetch(
        `${STORYBLOK_BASE_URL}/${fullSlug}?token=${STORYBLOK_TOKEN}&version=draft`
      );

      if (!response.ok) {
        console.error("Failed to fetch post with slug:", fullSlug);
        return null;
      }

      const data = await response.json();
      const story = data.story;
      const { content, created_at, id, tag_list } = story;

      return {
        id: id.toString(),
        slug: story.slug,
        title: content.title || story.name,
        excerpt: content.excerpt || '',
        content: content.content || '',
        author: content.author || 'PHA Contributor',
        date: new Date(created_at).toLocaleDateString('en-GB', { 
          day: 'numeric', 
          month: 'short', 
          year: 'numeric' 
        }),
        readTime: `${Math.max(1, Math.ceil((content.content?.split(' ').length || 0) / 200))} min read`,
        category: content.category || 'Tech',
        image: content.image?.filename || 'https://images.unsplash.com/photo-1519389950473-47ba0277781c?auto=format&fit=crop&q=80&w=1000',
        isFeatured: tag_list?.includes('featured') || false
      };
    } catch (error) {
      console.error("Error fetching single post:", error);
      return null;
    }
  }
};

